import React, { useEffect, useState } from "react";
import Dashboard from "./Dashboard";
import AddTask from "./AddTask";

export default function TaskList() {
  const [tasks, setTasks] = useState([]);
  // const [notifications, setNotifications] = useState([]);
  const [showAddModal, setShowAddModal] = useState(false); // ✅ NEW

  const fetchAll = async () => {
    try {
      const t = await fetch("http://localhost:8086/tasks").then(r => r.json());
      const n = await fetch("http://localhost:8086/tasks/notifications").then(r => r.json());

      setTasks(t);
      setNotifications(n);
    } catch (err) {
      console.error("Error fetching data:", err);
    }
  };

  useEffect(() => { fetchAll(); }, []);



  const completeTask = async (id) => {
    await fetch(`http://localhost:8086/tasks/${id}/complete`, {
      method: "PUT"
    });
    fetchAll();
  };

  return (
    <div className="bg-gray-100 min-h-screen p-6">
      <Dashboard />

      {/* ✅ ADD TASK BUTTON */}
      <button
        onClick={() => setShowAddModal(true)}
        className="bg-blue-600 text-white px-5 py-3 rounded-xl shadow hover:bg-blue-700 transition mb-4"
      >
        + Add Task
      </button>

      {/* ✅ MODAL */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm flex justify-center items-center z-50">
          <AddTask
            closeModal={() => setShowAddModal(false)}
            onTaskAdded={() => {
              fetchAll();
              setShowAddModal(false);
            }}
          />
        </div>
      )}

      {/* Tasks */}
      <div className="space-y-3">
        {tasks.map(t => (
          <div
            key={t.id}
            className="bg-white p-4 rounded-xl shadow flex justify-between items-center"
          >
            <div>
              <div className="font-semibold text-gray-800">{t.title}</div>
              <div className="text-sm text-gray-500">
                {t.priority} | {t.dueDate}
              </div>
            </div>

            {!t.completed && (
              <button
                onClick={() => completeTask(t.id)}
                className="bg-green-500 text-white px-4 py-2 rounded-lg hover:bg-green-600"
              >
                Done
              </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
